--
-- Table structure for table `villages`
--

DROP TABLE IF EXISTS `villages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `villages` (
  `id` int(11) unsigned NOT NULL,
  `district_id` int(11) unsigned NOT NULL,
  `code` varchar(10) NOT NULL,
  `name` varchar(100) NOT NULL,
  `postal_code` varchar(10) DEFAULT NULL,
  `area_code` varchar(10) DEFAULT NULL,
  `urban_classification` varchar(20) DEFAULT NULL,
  `development_index` decimal(5,2) DEFAULT NULL,
  `center_latitude` decimal(10,8) DEFAULT NULL,
  `center_longitude` decimal(11,8) DEFAULT NULL,
  `center_point` point DEFAULT NULL,
  `population` bigint(20) DEFAULT NULL,
  `population_density` decimal(10,2) DEFAULT NULL,
  `male_population` bigint(20) DEFAULT NULL,
  `female_population` bigint(20) DEFAULT NULL,
  `household_count` int(11) DEFAULT NULL,
  `average_household_size` decimal(4,2) DEFAULT NULL,
  `boundary_area_km2` decimal(8,2) DEFAULT NULL,
  `village_type` varchar(20) DEFAULT NULL,
  `village_head` varchar(100) DEFAULT NULL,
  `established` year(4) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `idx_district_id` (`district_id`),
  KEY `idx_code` (`code`),
  KEY `idx_postal_code` (`postal_code`),
  KEY `idx_villages_population` (`population`),
  KEY `idx_villages_center_point` (`center_point`(25)),
  KEY `idx_villages_urban_classification` (`urban_classification`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

